    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["column"], str) or not is_valid_identifier(op["column"]):
        return f"operation {i}: invalid column name '{op.get('column')}'"
    if not isinstance(op["value"], str):
        return f"operation {i}: value must be a string"

    if "where" in op and not isinstance(op["where"], str):
        return f"operation {i}: where must be a string"

elif op_type == "add_foreign_key":
    for req_field in ("table", "name", "columns", "references"):
        if req_field not in op:
            return f"operation {i}: missing required field '{req_field}'"
    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid foreign key name '{op.get('name')}'"
    if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
        return f"operation {i}: columns must be a non-empty array"
    for j, col in enumerate(op["columns"]):
        if not isinstance(col, str) or not is_valid_identifier(col):
            return f"operation {i}: invalid column name at index {j}"
    if not isinstance(op["references"], dict):
        return f"operation {i}: references must be an object"
    if "table" not in op["references"] or "columns" not in op["references"]:
        return f"operation {i}: references must have 'table' and 'columns'"
    if not isinstance(op["references"]["table"], str) or not is_valid_identifier(op["references"]["table"]):
        return f"operation {i}: invalid referenced table name"
    if not isinstance(op["references"]["columns"], list) or len(op["references"]["columns"]) == 0:
        return f"operation {i}: references.columns must be a non-empty array"
    if len(op["columns"]) != len(op["references"]["columns"]):
        return f"operation {i}: number of columns must match references.columns"
    for j, col in enumerate(op["references"]["columns"]):
        if not isinstance(col, str) or not is_valid_identifier(col):
            return f"operation {i}: invalid referenced column name at index {j}"
    if "on_delete" in op:
        if not isinstance(op["on_delete"], str) or op["on_delete"] not in VALID_FK_ACTIONS:
            return f"operation {i}: invalid on_delete action '{op.get('on_delete')}'"
    if "on_update" in op:
        if not isinstance(op["on_update"], str) or op["on_update"] not in VALID_FK_ACTIONS:
            return f"operation {i}: invalid on_update action '{op.get('on_update')}'"

elif op_type == "drop_foreign_key":
    for req_field in ("table", "name"):
        if req_field not in op:
            return f"operation {i}: missing required field '{req_field}'"
    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid foreign key name '{op.get('name')}'"

elif op_type == "create_index":
    for req_field in ("name", "table", "columns"):
        if req_field not in op:
            return f"operation {i}: missing required field '{req_field}'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid index name '{op.get('name')}'"
    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
        return f"operation {i}: columns must be a non-empty array"
    for j, col in enumerate(op["columns"]):
        if not isinstance(col, str) or not is_valid_identifier(col):
            return f"operation {i}: invalid column name at index {j}"
    if "unique" in op and not isinstance(op["unique"], bool):
        return f"operation {i}: unique must be a boolean"

elif op_type == "drop_index":
    if "name" not in op:
        return f"operation {i}: missing required field 'name'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid index name '{op.get('name')}'"

elif op_type == "add_check_constraint":
    for req_field in ("table", "name", "expression"):
        if req_field not in op:
            return f"operation {i}: missing required field '{req_field}'"
    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid constraint name '{op.get('name')}'"
    if not isinstance(op["expression"], str):
        return f"operation {i}: expression must be a string"

elif op_type == "drop_check_constraint":
    for req_field in ("table", "name"):
        if req_field not in op:
            return f"operation {i}: missing required field '{req_field}'"
    if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
        return f"operation {i}: invalid table name '{op.get('table')}'"
    if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
        return f"operation {i}: invalid constraint name '{op.get('name')}'"

else:
    return f"operation {i}: unknown operation type '{op_type}'"

