#!/usr/bin/env python3
"""Database Migration Tool - Applies schema migrations to SQLite databases."""

import argparse
import json
import os
import re
import sqlite3
import sys


VALID_SQLITE_TYPES = {"INTEGER", "TEXT", "REAL", "BLOB", "TIMESTAMP"}
VALID_FK_ACTIONS = {"CASCADE", "RESTRICT", "SET NULL", "NO ACTION", "SET DEFAULT"}


class MigrationError(Exception):
    """Exception raised when a migration operation fails."""
    pass


def error_exit(message):
    """Print error to stderr and exit with code 1."""
    print(f"Error: {message}", file=sys.stderr)
    sys.exit(1)


def is_valid_identifier(name):
    """Check if a name is a valid SQLite identifier (alphanumeric + underscore, starts with letter/underscore)."""
    if not name or not isinstance(name, str):
        return False
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', name))


def quote_identifier(name):
    """Quote a SQLite identifier to prevent SQL injection."""
    # Double any existing double quotes, then wrap in double quotes
    return '"' + name.replace('"', '""') + '"'


def validate_column(col, operation_type="create_table"):
    """Validate a column definition. Returns error message or None."""
    if not isinstance(col, dict):
        return "column must be an object"

    if "name" not in col:
        return "missing required field 'name' in column definition"
    if "type" not in col:
        return "missing required field 'type' in column definition"

    if not isinstance(col["name"], str) or not is_valid_identifier(col["name"]):
        return f"invalid column name: '{col.get('name')}'"
    if not isinstance(col["type"], str) or col["type"].upper() not in VALID_SQLITE_TYPES:
        return f"invalid column type: '{col.get('type')}'"

    # Validate optional boolean fields
    for bool_field in ("primary_key", "auto_increment", "not_null", "unique"):
        if bool_field in col and not isinstance(col[bool_field], bool):
            return f"field '{bool_field}' must be a boolean"

    # auto_increment must be on INTEGER primary key
    if col.get("auto_increment", False):
        if col["type"].upper() != "INTEGER":
            return "auto_increment can only be used with INTEGER type"
        if not col.get("primary_key", False):
            return "auto_increment can only be used with primary_key"

    return None


def validate_migration(migration):
    """Validate the migration JSON structure. Returns error message or None."""
    if not isinstance(migration, dict):
        return "migration must be a JSON object"

    if "version" not in migration:
        return "missing required field 'version'"
    if "description" not in migration:
        return "missing required field 'description'"
    if "operations" not in migration:
        return "missing required field 'operations'"

    if not isinstance(migration["version"], int) or migration["version"] <= 0:
        return "version must be a positive integer"
    if not isinstance(migration["description"], str):
        return "description must be a string"
    if not isinstance(migration["operations"], list):
        return "operations must be an array"
    if len(migration["operations"]) == 0:
        return "operations array must not be empty"

    for i, op in enumerate(migration["operations"]):
        if not isinstance(op, dict):
            return f"operation {i} must be an object"
        if "type" not in op:
            return f"operation {i}: missing required field 'type'"

        op_type = op["type"]

        if op_type == "create_table":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "columns" not in op:
                return f"operation {i}: missing required field 'columns'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"

            pk_count = 0
            for j, col in enumerate(op["columns"]):
                err = validate_column(col, "create_table")
                if err:
                    return f"operation {i}, column {j}: {err}"
                if col.get("primary_key", False):
                    pk_count += 1
            if pk_count > 1:
                return f"operation {i}: at most one column can have primary_key=true"

        elif op_type == "add_column":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"

            err = validate_column(op["column"], "add_column")
            if err:
                return f"operation {i}: {err}"

        elif op_type == "drop_column":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["column"], str) or not is_valid_identifier(op["column"]):
                return f"operation {i}: invalid column name '{op.get('column')}'"

        elif op_type == "transform_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "transformations" not in op:
                return f"operation {i}: missing required field 'transformations'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"

            if not isinstance(op["transformations"], list) or len(op["transformations"]) == 0:
                return f"operation {i}: transformations must be a non-empty array"

            for j, transform in enumerate(op["transformations"]):
                if not isinstance(transform, dict):
                    return f"operation {i}, transformation {j}: must be an object"
                if "column" not in transform:
                    return f"operation {i}, transformation {j}: missing required field 'column'"
                if "expression" not in transform:
                    return f"operation {i}, transformation {j}: missing required field 'expression'"
                if not isinstance(transform["column"], str) or not is_valid_identifier(transform["column"]):
                    return f"operation {i}, transformation {j}: invalid column name '{transform.get('column')}'"
                if not isinstance(transform["expression"], str):
                    return f"operation {i}, transformation {j}: expression must be a string"

        elif op_type == "migrate_column_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "from_column" not in op:
                return f"operation {i}: missing required field 'from_column'"
            if "to_column" not in op:
                return f"operation {i}: missing required field 'to_column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["from_column"], str) or not is_valid_identifier(op["from_column"]):
                return f"operation {i}: invalid from_column name '{op.get('from_column')}'"
            if not isinstance(op["to_column"], str) or not is_valid_identifier(op["to_column"]):
                return f"operation {i}: invalid to_column name '{op.get('to_column')}'"

            if "default_value" in op and op["default_value"] is not None and not isinstance(op["default_value"], str):
                return f"operation {i}: default_value must be a string or null"

        elif op_type == "backfill_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"
            if "value" not in op:
                return f"operation {i}: missing required field 'value'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["column"], str) or not is_valid_identifier(op["column"]):
                return f"operation {i}: invalid column name '{op.get('column')}'"
            if not isinstance(op["value"], str):
                return f"operation {i}: value must be a string"

            if "where" in op and not isinstance(op["where"], str):
                return f"operation {i}: where must be a string"

        elif op_type == "add_foreign_key":
            for req_field in ("table", "name", "columns", "references"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid foreign key name '{op.get('name')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"
            for j, col in enumerate(op["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid column name at index {j}"
            if not isinstance(op["references"], dict):
                return f"operation {i}: references must be an object"
            if "table" not in op["references"] or "columns" not in op["references"]:
                return f"operation {i}: references must have 'table' and 'columns'"
            if not isinstance(op["references"]["table"], str) or not is_valid_identifier(op["references"]["table"]):
                return f"operation {i}: invalid referenced table name"
            if not isinstance(op["references"]["columns"], list) or len(op["references"]["columns"]) == 0:
                return f"operation {i}: references.columns must be a non-empty array"
            if len(op["columns"]) != len(op["references"]["columns"]):
                return f"operation {i}: number of columns must match references.columns"
            for j, col in enumerate(op["references"]["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid referenced column name at index {j}"
            if "on_delete" in op:
                if not isinstance(op["on_delete"], str) or op["on_delete"] not in VALID_FK_ACTIONS:
                    return f"operation {i}: invalid on_delete action '{op.get('on_delete')}'"
            if "on_update" in op:
                if not isinstance(op["on_update"], str) or op["on_update"] not in VALID_FK_ACTIONS:
                    return f"operation {i}: invalid on_update action '{op.get('on_update')}'"

        elif op_type == "drop_foreign_key":
            for req_field in ("table", "name"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid foreign key name '{op.get('name')}'"

        elif op_type == "create_index":
            for req_field in ("name", "table", "columns"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid index name '{op.get('name')}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"
            for j, col in enumerate(op["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid column name at index {j}"
            if "unique" in op and not isinstance(op["unique"], bool):
                return f"operation {i}: unique must be a boolean"

        elif op_type == "drop_index":
            if "name" not in op:
                return f"operation {i}: missing required field 'name'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid index name '{op.get('name')}'"

        elif op_type == "add_check_constraint":
            for req_field in ("table", "name", "expression"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid constraint name '{op.get('name')}'"
            if not isinstance(op["expression"], str):
                return f"operation {i}: expression must be a string"

        elif op_type == "drop_check_constraint":
            for req_field in ("table", "name"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid constraint name '{op.get('name')}'"

        else:
            return f"operation {i}: unknown operation type '{op_type}'"

    return None


def build_column_sql(col):
    """Build the SQL fragment for a column definition."""
    parts = [quote_identifier(col["name"]), col["type"].upper()]

    if col.get("primary_key", False):
        parts.append("PRIMARY KEY")
        if col.get("auto_increment", False):
            parts.append("AUTOINCREMENT")

    if col.get("not_null", False):
        parts.append("NOT NULL")

    if col.get("unique", False):
        parts.append("UNIQUE")

    if "default" in col and col["default"] is not None:
        parts.append(f"DEFAULT {col['default']}")

    return " ".join(parts)


def get_table_info(conn, table_name):
    """Get column info for a table. Returns list of column info dicts."""
    cursor = conn.execute(f"PRAGMA table_info({quote_identifier(table_name)})")
    columns = []
    for row in cursor.fetchall():
        columns.append({
            "cid": row[0],
            "name": row[1],
            "type": row[2],
            "not_null": bool(row[3]),
            "default_value": row[4],
            "primary_key": bool(row[5]),
        })
    return columns


def table_exists(conn, table_name):
    """Check if a table exists in the database."""
    cursor = conn.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    return cursor.fetchone() is not None


def column_exists(conn, table_name, column_name):
    """Check if a column exists in a table."""
    columns = get_table_info(conn, table_name)
    return any(c["name"] == column_name for c in columns)


def get_column_names(conn, table_name):
    """Get list of column names for a table."""
    columns = get_table_info(conn, table_name)
    return [c["name"] for c in columns]


def index_exists(conn, index_name):
    """Check if an index exists in the database."""
    cursor = conn.execute(
        "SELECT name FROM sqlite_master WHERE type='index' AND name=?",
        (index_name,)
    )
    return cursor.fetchone() is not None


def get_table_foreign_keys(conn, table_name):
    """Get foreign key constraints for a table using PRAGMA foreign_key_list."""
    cursor = conn.execute(f"PRAGMA foreign_key_list({quote_identifier(table_name)})")
    fks = []
    for row in cursor.fetchall():
        fks.append({
            "id": row[0],        # Foreign key id (for composite FKs)
            "seq": row[1],       # Column sequence in composite FK
            "table": row[2],     # Referenced table
            "from": row[3],      # Column in this table
            "to": row[4],        # Column in referenced table
            "on_update": row[5],
            "on_delete": row[6],
            "match": row[7],
        })
    return fks


def get_foreign_key_id_by_name(conn, table_name, fk_name):
    """
    Get foreign key constraint info by name.
    SQLite doesn't store FK names directly, so we parse them from the CREATE TABLE SQL.
    Returns dict with 'id' (the FK id from pragma) and other info, or None if not found.
    """
    cursor = conn.execute(
        "SELECT sql FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    row = cursor.fetchone()
    if not row or not row[0]:
        return None

    sql = row[0]
    # Find CONSTRAINT <name> FOREIGN KEY pattern
    # Pattern matches: CONSTRAINT "name" or CONSTRAINT name
    import re
    pattern = r'CONSTRAINT\s+"?' + re.escape(fk_name) + r'"\s+FOREIGN\s+KEY\s*\(([^)]+)\)\s+REFERENCES\s+"?(\w+)"?\s*\(([^)]+)\)(?:\s+ON\s+DELETE\s+(CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?(?:\s+ON\s+UPDATE\s+(CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?'
    match = re.search(pattern, sql, re.IGNORECASE)
    if not match:
        return None

    columns_str = match.group(1)
    ref_table = match.group(2)
    ref_columns_str = match.group(3)
    on_delete = match.group(4)
    on_update = match.group(5)

    # Parse column names (remove quotes)
    columns = [c.strip().strip('"') for c in columns_str.split(',')]
    ref_columns = [c.strip().strip('"') for c in ref_columns_str.split(',')]

    # Find the FK id from pragma
    pragma_fks = get_table_foreign_keys(conn, table_name)
    for fk in pragma_fks:
        if fk["table"] == ref_table and fk["from"] == columns[0]:
            return {
                "id": fk["id"],
                "name": fk_name,
                "columns": columns,
                "references": {
                    "table": ref_table,
                    "columns": ref_columns
                },
                "on_delete": on_delete,
                "on_update": on_update
            }

    return None


def get_table_indexes(conn, table_name):
    """Get indexes for a table using PRAGMA index_list."""
    cursor = conn.execute(f"PRAGMA index_list({quote_identifier(table_name)})")
    indexes = []
    for row in cursor.fetchall():
        indexes.append({
            "name": row[1],
            "unique": bool(row[2]),
            "origin": row[3] if len(row) > 3 else "c",
        })
    return indexes


def get_index_columns(conn, index_name):
    """Get columns for an index using PRAGMA index_info."""
    cursor = conn.execute(f"PRAGMA index_info({quote_identifier(index_name)})")
    columns = []
    for row in cursor.fetchall():
        columns.append(row[2])  # Column name is at index 2
    return columns


def get_table_create_sql(conn, table_name):
    """Get the CREATE TABLE SQL for a table."""
    cursor = conn.execute(
        "SELECT sql FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    row = cursor.fetchone()
    return row[0] if row else None


def get_check_constraints_from_sql(sql):
    """Parse check constraints from CREATE TABLE SQL."""
    import re
    constraints = []
    # Pattern for CONSTRAINT name CHECK (expression)
    pattern = r'CONSTRAINT\s+"?(\w+)"?\s+CHECK\s*\(([^)]+(?:\([^)]*\)[^)]*)*)\)'
    for match in re.finditer(pattern, sql, re.IGNORECASE):
        constraints.append({
            "name": match.group(1),
            "expression": match.group(2).strip()
        })
    return constraints


def check_constraint_exists(conn, table_name, constraint_name):
    """Check if a check constraint exists on a table."""
    sql = get_table_create_sql(conn, table_name)
    if not sql:
        return False
    constraints = get_check_constraints_from_sql(sql)
    return any(c["name"] == constraint_name for c in constraints)


def init_migrations_table(conn):
    """Create the _migrations tracking table if it doesn't exist."""
    conn.execute("""
        CREATE TABLE IF NOT EXISTS _migrations (
            version INTEGER PRIMARY KEY,
            description TEXT NOT NULL,
            applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)
    conn.commit()


def is_migration_applied(conn, version):
    """Check if a migration version has already been applied."""
    cursor = conn.execute(
        "SELECT version FROM _migrations WHERE version = ?",
        (version,)
    )
    return cursor.fetchone() is not None


def record_migration(conn, version, description):
    """Record a successfully applied migration."""
    conn.execute(
        "INSERT INTO _migrations (version, description) VALUES (?, ?)",
        (version, description)
    )


def apply_create_table(conn, op, version):
    """Apply a create_table operation."""
    table_name = op["table"]

    if table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' already exists")

    col_defs = [build_column_sql(col) for col in op["columns"]]
    sql = f"CREATE TABLE {quote_identifier(table_name)} ({', '.join(col_defs)})"
    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "create_table",
        "table": table_name,
        "version": version
    }))


def apply_add_column(conn, op, version):
    """Apply an add_column operation."""
    table_name = op["table"]
    col = op["column"]
    col_name = col["name"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if column_exists(conn, table_name, col_name):
        raise MigrationError(f"invalid operation: column '{col_name}' already exists in table '{table_name}'")

    col_sql = build_column_sql(col)
    sql = f"ALTER TABLE {quote_identifier(table_name)} ADD COLUMN {col_sql}"
    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "add_column",
        "table": table_name,
        "column": col_name,
        "version": version
    }))


def apply_drop_column(conn, op, version):
    """Apply a drop_column operation by recreating the table."""
    table_name = op["table"]
    col_name = op["column"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    columns = get_table_info(conn, table_name)
    col_names = [c["name"] for c in columns]

    if col_name not in col_names:
        raise MigrationError(f"invalid operation: column '{col_name}' does not exist in table '{table_name}'")

    # Cannot drop if it's the only column
    if len(columns) <= 1:
        raise MigrationError(f"invalid operation: cannot drop the only column in table '{table_name}'")

    # Cannot drop a PRIMARY KEY column
    col_info = next(c for c in columns if c["name"] == col_name)
    if col_info["primary_key"]:
        raise MigrationError(f"invalid operation: cannot drop PRIMARY KEY column '{col_name}'")

    keep_columns = [c for c in columns if c["name"] != col_name]
    keep_names = [c["name"] for c in keep_columns]

    col_defs = []
    for c in keep_columns:
        parts = [quote_identifier(c["name"]), c["type"]]
        if c["primary_key"]:
            parts.append("PRIMARY KEY")
        if c["not_null"]:
            parts.append("NOT NULL")
        if c["default_value"] is not None:
            parts.append(f"DEFAULT {c['default_value']}")
        col_defs.append(" ".join(parts))

    temp_table_name = f"_temp_migration_{table_name}"

    try:
        create_sql = f"CREATE TABLE {quote_identifier(temp_table_name)} ({', '.join(col_defs)})"
        conn.execute(create_sql)

        cols_str = ", ".join(quote_identifier(c) for c in keep_names)
        copy_sql = (
            f"INSERT INTO {quote_identifier(temp_table_name)} ({cols_str}) "
            f"SELECT {cols_str} FROM {quote_identifier(table_name)}"
        )
        conn.execute(copy_sql)

        conn.execute(f"DROP TABLE {quote_identifier(table_name)}")

        conn.execute(
            f"ALTER TABLE {quote_identifier(temp_table_name)} RENAME TO {quote_identifier(table_name)}"
        )
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "drop_column",
        "table": table_name,
        "column": col_name,
        "version": version
    }))


def apply_transform_data(conn, op, version):
    """Apply a transform_data operation."""
    table_name = op["table"]
    transformations = op["transformations"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    for transform in transformations:
        col_name = transform["column"]
        expression = transform["expression"]

        if not column_exists(conn, table_name, col_name):
            raise MigrationError(f"invalid operation: column '{col_name}' does not exist in table '{table_name}'")

        sql = (
            f"UPDATE {quote_identifier(table_name)} "
            f"SET {quote_identifier(col_name)} = {expression}"
        )
        try:
            conn.execute(sql)
        except sqlite3.OperationalError as e:
            raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "transform_data",
        "table": table_name,
        "transformations_count": len(transformations),
        "version": version
    }))


def apply_migrate_column_data(conn, op, version):
    """Apply a migrate_column_data operation."""
    table_name = op["table"]
    from_col = op["from_column"]
    to_col = op["to_column"]
    default_value = op.get("default_value")

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if not column_exists(conn, table_name, from_col):
        raise MigrationError(f"invalid operation: column '{from_col}' does not exist in table '{table_name}'")

    if not column_exists(conn, table_name, to_col):
        raise MigrationError(f"invalid operation: column '{to_col}' does not exist in table '{table_name}'")

    if default_value is not None:
        sql = (
            f"UPDATE {quote_identifier(table_name)} "
            f"SET {quote_identifier(to_col)} = CASE "
            f"WHEN {quote_identifier(from_col)} IS NOT NULL THEN {quote_identifier(from_col)} "
            f"ELSE {default_value} END"
        )
    else:
        sql = (
            f"UPDATE {quote_identifier(table_name)} "
            f"SET {quote_identifier(to_col)} = {quote_identifier(from_col)}"
        )

    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "migrate_column_data",
        "table": table_name,
        "from_column": from_col,
        "to_column": to_col,
        "version": version
    }))


def apply_backfill_data(conn, op, version):
    """Apply a backfill_data operation."""
    table_name = op["table"]
    col_name = op["column"]
    value = op["value"]
    where_clause = op.get("where")

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if not column_exists(conn, table_name, col_name):
        raise MigrationError(f"invalid operation: column '{col_name}' does not exist in table '{table_name}'")

    sql = (
        f"UPDATE {quote_identifier(table_name)} "
        f"SET {quote_identifier(col_name)} = {value}"
    )
    if where_clause:
        sql += f" WHERE {where_clause}"

    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "backfill_data",
        "table": table_name,
        "column": col_name,
        "version": version
    }))


def apply_add_foreign_key(conn, op, version):
    """Apply an add_foreign_key operation by recreating the table."""
    table_name = op["table"]
    fk_name = op["name"]
    columns = op["columns"]
    ref_table = op["references"]["table"]
    ref_columns = op["references"]["columns"]
    on_delete = op.get("on_delete", "NO ACTION")
    on_update = op.get("on_update", "NO ACTION")

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if not table_exists(conn, ref_table):
        raise MigrationError(f"cannot add foreign key: referenced table '{ref_table}' does not exist")

    # Check that all referencing columns exist
    table_cols = get_column_names(conn, table_name)
    for col in columns:
        if col not in table_cols:
            raise MigrationError(f"cannot add foreign key: column '{col}' does not exist in table '{table_name}'")

    # Check that all referenced columns exist
    ref_table_cols = get_column_names(conn, ref_table)
    for col in ref_columns:
        if col not in ref_table_cols:
            raise MigrationError(f"cannot add foreign key: referenced column '{ref_table}.{col}' does not exist")

    # Check if FK already exists (by parsing CREATE TABLE SQL)
    existing_fk = get_foreign_key_id_by_name(conn, table_name, fk_name)
    if existing_fk:
        raise MigrationError(f"foreign key '{fk_name}' already exists on table '{table_name}'")

    # Build foreign key constraint clause
    cols_str = ", ".join(quote_identifier(c) for c in columns)
    ref_cols_str = ", ".join(quote_identifier(c) for c in ref_columns)
    fk_clause = f'CONSTRAINT {quote_identifier(fk_name)} FOREIGN KEY ({cols_str}) REFERENCES {quote_identifier(ref_table)}({ref_cols_str})'
    if on_delete and on_delete != "NO ACTION":
        fk_clause += f' ON DELETE {on_delete}'
    if on_update and on_update != "NO ACTION":
        fk_clause += f' ON UPDATE {on_update}'

    # Get current table SQL and modify it
    current_sql = get_table_create_sql(conn, table_name)
    if not current_sql:
        raise MigrationError(f"cannot get schema for table '{table_name}'")

    # Find the last closing parenthesis before any trailing parts
    # Insert FK constraint before the closing parenthesis
    import re
    match = re.search(r'\)(\s*;?\s*)$', current_sql)
    if match:
        new_sql = current_sql[:match.start()] + f', {fk_clause})' + current_sql[match.end()-1:]
    else:
        # Try to find the closing parenthesis of column definitions
        paren_depth = 0
        insert_pos = -1
        for i, ch in enumerate(current_sql):
            if ch == '(':
                paren_depth += 1
            elif ch == ')':
                paren_depth -= 1
                if paren_depth == 0:
                    insert_pos = i
                    break
        if insert_pos == -1:
            raise MigrationError(f"cannot parse table schema for '{table_name}'")
        new_sql = current_sql[:insert_pos] + f', {fk_clause})' + current_sql[insert_pos+1:]

    temp_table_name = f"_temp_migration_{table_name}"

    try:
        conn.execute(f"DROP TABLE IF EXISTS {quote_identifier(temp_table_name)}")
        conn.execute(new_sql.replace(f'CREATE TABLE {quote_identifier(table_name)}', f'CREATE TABLE {quote_identifier(temp_table_name)}'))

        # Get column order for insert
        cols = get_column_names(conn, table_name)
        cols_str = ", ".join(quote_identifier(c) for c in cols)
        conn.execute(f"INSERT INTO {quote_identifier(temp_table_name)} ({cols_str}) SELECT {cols_str} FROM {quote_identifier(table_name)}")

        conn.execute(f"DROP TABLE {quote_identifier(table_name)}")
        conn.execute(f"ALTER TABLE {quote_identifier(temp_table_name)} RENAME TO {quote_identifier(table_name)}")

        # Enable FK and verify
        conn.execute("PRAGMA foreign_keys = ON")
        try:
            conn.execute(f"SELECT 1 FROM {quote_identifier(table_name)} LIMIT 1")
        except sqlite3.IntegrityError as e:
            raise MigrationError(f"foreign key violation: {str(e)}")
        conn.execute("PRAGMA foreign_keys = OFF")

    except sqlite3.IntegrityError as e:
        raise MigrationError(f"foreign key violation: {str(e)}")
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "add_foreign_key",
        "table": table_name,
        "name": fk_name,
        "version": version
    }))


def apply_drop_foreign_key(conn, op, version):
    """Apply a drop_foreign_key operation by recreating the table."""
    table_name = op["table"]
    fk_name = op["name"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    # Find the FK constraint
    fk_info = get_foreign_key_id_by_name(conn, table_name, fk_name)
    if not fk_info:
        raise MigrationError(f"foreign key '{fk_name}' does not exist on table '{table_name}'")

    # Get current table SQL and remove the FK constraint
    current_sql = get_table_create_sql(conn, table_name)
    if not current_sql:
        raise MigrationError(f"cannot get schema for table '{table_name}'")

    # Remove the constraint using regex
    import re
    # Pattern to match CONSTRAINT "fk_name" FOREIGN KEY ... (with possible ON DELETE/ON UPDATE)
    pattern = r',?\s*CONSTRAINT\s+"?' + re.escape(fk_name) + r'"\s+FOREIGN\s+KEY\s*\([^)]+\)\s+REFERENCES\s+"?\w+"?\s*\([^)]+\)(?:\s+ON\s+DELETE\s+(?:CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?(?:\s+ON\s+UPDATE\s+(?:CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?'
    new_sql = re.sub(pattern, '', current_sql, flags=re.IGNORECASE)

    # Clean up any leading commas after removing constraint
    new_sql = re.sub(r'\(\s*,', '(', new_sql)

    temp_table_name = f"_temp_migration_{table_name}"

    try:
        conn.execute(f"DROP TABLE IF EXISTS {quote_identifier(temp_table_name)}")
        conn.execute(new_sql.replace(f'CREATE TABLE {quote_identifier(table_name)}', f'CREATE TABLE {quote_identifier(temp_table_name)}'))

        # Get column order for insert
        cols = get_column_names(conn, table_name)
        cols_str = ", ".join(quote_identifier(c) for c in cols)
        conn.execute(f"INSERT INTO {quote_identifier(temp_table_name)} ({cols_str}) SELECT {cols_str} FROM {quote_identifier(table_name)}")

        conn.execute(f"DROP TABLE {quote_identifier(table_name)}")
        conn.execute(f"ALTER TABLE {quote_identifier(temp_table_name)} RENAME TO {quote_identifier(table_name)}")

    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "drop_foreign_key",
        "table": table_name,
        "name": fk_name,
        "version": version
    }))


def apply_create_index(conn, op, version):
    """Apply a create_index operation."""
    index_name = op["name"]
    table_name = op["table"]
    columns = op["columns"]
    unique = op.get("unique", False)

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    # Check all columns exist
    table_cols = get_column_names(conn, table_name)
    for col in columns:
        if col not in table_cols:
            raise MigrationError(f"invalid operation: column '{col}' does not exist in table '{table_name}'")

    if index_exists(conn, index_name):
        raise MigrationError(f"index '{index_name}' already exists")

    unique_clause = "UNIQUE " if unique else ""
    cols_str = ", ".join(quote_identifier(c) for c in columns)
    sql = f"CREATE {unique_clause}INDEX {quote_identifier(index_name)} ON {quote_identifier(table_name)} ({cols_str})"

    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "create_index",
        "name": index_name,
        "table": table_name,
        "version": version
    }))


def apply_drop_index(conn, op, version):
    """Apply a drop_index operation."""
    index_name = op["name"]

    if not index_exists(conn, index_name):
        raise MigrationError(f"index '{index_name}' does not exist")

    sql = f"DROP INDEX {quote_identifier(index_name)}"

    try:
        conn.execute(sql)
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "drop_index",
        "name": index_name,
        "version": version
    }))


def apply_add_check_constraint(conn, op, version):
    """Apply an add_check_constraint operation by recreating the table."""
    table_name = op["table"]
    constraint_name = op["name"]
    expression = op["expression"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if check_constraint_exists(conn, table_name, constraint_name):
        raise MigrationError(f"check constraint '{constraint_name}' already exists on table '{table_name}'")

    # Get current table SQL and add the constraint
    current_sql = get_table_create_sql(conn, table_name)
    if not current_sql:
        raise MigrationError(f"cannot get schema for table '{table_name}'")

    # Add CHECK constraint
    import re
    match = re.search(r'\)(\s*;?\s*)$', current_sql)
    if match:
        new_sql = current_sql[:match.start()] + f', CONSTRAINT {quote_identifier(constraint_name)} CHECK ({expression}))' + current_sql[match.end()-1:]
    else:
        paren_depth = 0
        insert_pos = -1
        for i, ch in enumerate(current_sql):
            if ch == '(':
                paren_depth += 1
            elif ch == ')':
                paren_depth -= 1
                if paren_depth == 0:
                    insert_pos = i
                    break
        if insert_pos == -1:
            raise MigrationError(f"cannot parse table schema for '{table_name}'")
        new_sql = current_sql[:insert_pos] + f', CONSTRAINT {quote_identifier(constraint_name)} CHECK ({expression}))' + current_sql[insert_pos+1:]

    temp_table_name = f"_temp_migration_{table_name}"

    try:
        conn.execute(f"DROP TABLE IF EXISTS {quote_identifier(temp_table_name)}")
        conn.execute(new_sql.replace(f'CREATE TABLE {quote_identifier(table_name)}', f'CREATE TABLE {quote_identifier(temp_table_name)}'))

        # Get column order for insert
        cols = get_column_names(conn, table_name)
        cols_str = ", ".join(quote_identifier(c) for c in cols)
        conn.execute(f"INSERT INTO {quote_identifier(temp_table_name)} ({cols_str}) SELECT {cols_str} FROM {quote_identifier(table_name)}")

        conn.execute(f"DROP TABLE {quote_identifier(table_name)}")
        conn.execute(f"ALTER TABLE {quote_identifier(temp_table_name)} RENAME TO {quote_identifier(table_name)}")

    except sqlite3.IntegrityError as e:
        raise MigrationError(f"check constraint violation: {str(e)}")
    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "add_check_constraint",
        "table": table_name,
        "name": constraint_name,
        "version": version
    }))


def apply_drop_check_constraint(conn, op, version):
    """Apply a drop_check_constraint operation by recreating the table."""
    table_name = op["table"]
    constraint_name = op["name"]

    if not table_exists(conn, table_name):
        raise MigrationError(f"invalid operation: table '{table_name}' does not exist")

    if not check_constraint_exists(conn, table_name, constraint_name):
        raise MigrationError(f"check constraint '{constraint_name}' does not exist on table '{table_name}'")

    # Get current table SQL and remove the constraint
    current_sql = get_table_create_sql(conn, table_name)
    if not current_sql:
        raise MigrationError(f"cannot get schema for table '{table_name}'")

    # Remove the constraint using regex
    import re
    pattern = r',?\s*CONSTRAINT\s+"?' + re.escape(constraint_name) + r'"\s+CHECK\s*\([^)]+(?:\([^)]*\)[^)]*)*\)'
    new_sql = re.sub(pattern, '', current_sql, flags=re.IGNORECASE)

    # Clean up any leading commas after removing constraint
    new_sql = re.sub(r'\(\s*,', '(', new_sql)

    temp_table_name = f"_temp_migration_{table_name}"

    try:
        conn.execute(f"DROP TABLE IF EXISTS {quote_identifier(temp_table_name)}")
        conn.execute(new_sql.replace(f'CREATE TABLE {quote_identifier(table_name)}', f'CREATE TABLE {quote_identifier(temp_table_name)}'))

        # Get column order for insert
        cols = get_column_names(conn, table_name)
        cols_str = ", ".join(quote_identifier(c) for c in cols)
        conn.execute(f"INSERT INTO {quote_identifier(temp_table_name)} ({cols_str}) SELECT {cols_str} FROM {quote_identifier(table_name)}")

        conn.execute(f"DROP TABLE {quote_identifier(table_name)}")
        conn.execute(f"ALTER TABLE {quote_identifier(temp_table_name)} RENAME TO {quote_identifier(table_name)}")

    except sqlite3.OperationalError as e:
        raise MigrationError(f"SQL error: {e}")

    print(json.dumps({
        "event": "operation_applied",
        "type": "drop_check_constraint",
        "table": table_name,
        "name": constraint_name,
        "version": version
    }))


def apply_migration(migration_file, db_file):
    """Apply a migration from a JSON file to a SQLite database."""
    if not os.path.exists(migration_file):
        error_exit(f"migration file not found: {migration_file}")

    try:
        with open(migration_file, 'r') as f:
            migration = json.load(f)
    except json.JSONDecodeError as e:
        error_exit(f"invalid JSON in migration file: {e}")
    except IOError as e:
        error_exit(f"cannot read migration file: {e}")

    err = validate_migration(migration)
    if err:
        error_exit(f"invalid migration schema: {err}")

    version = migration["version"]
    description = migration["description"]
    operations = migration["operations"]

    try:
        conn = sqlite3.connect(db_file)
    except sqlite3.Error as e:
        error_exit(f"cannot open database: {e}")

    try:
        conn.execute("PRAGMA foreign_keys = OFF")

        init_migrations_table(conn)

        if is_migration_applied(conn, version):
            print(f"Warning: Migration version {version} already applied, skipping", file=sys.stderr)
            print(json.dumps({
                "event": "migration_skipped",
                "version": version,
                "reason": "already_applied"
            }))
            conn.close()
            return

        for op in operations:
            op_type = op["type"]
            if op_type == "create_table":
                apply_create_table(conn, op, version)
            elif op_type == "add_column":
                apply_add_column(conn, op, version)
            elif op_type == "drop_column":
                apply_drop_column(conn, op, version)
            elif op_type == "transform_data":
                apply_transform_data(conn, op, version)
            elif op_type == "migrate_column_data":
                apply_migrate_column_data(conn, op, version)
            elif op_type == "backfill_data":
                apply_backfill_data(conn, op, version)

        record_migration(conn, version, description)
        conn.commit()

        print(json.dumps({
            "event": "migration_complete",
            "version": version,
            "operations_count": len(operations)
        }))

    except MigrationError as e:
        conn.rollback()
        conn.close()
        error_exit(str(e))
    except Exception as e:
        conn.rollback()
        conn.close()
        error_exit(str(e))
    finally:
        conn.close()


def main():
    parser = argparse.ArgumentParser(description="Database Migration Tool")
    subparsers = parser.add_subparsers(dest="command")

    migrate_parser = subparsers.add_parser("migrate", help="Apply a migration")
    migrate_parser.add_argument("migration_file", help="Path to migration JSON file")
    migrate_parser.add_argument("database", help="Path to SQLite database file")

    args = parser.parse_args()

    if args.command == "migrate":
        apply_migration(args.migration_file, args.database)
    else:
        parser.print_help()
        sys.exit(1)


if __name__ == "__main__":
