#!/usr/bin/env python3
"""Database Migration Tool - Applies schema migrations to SQLite databases."""

import argparse
import json
import os
import re
import sqlite3
import sys


VALID_SQLITE_TYPES = {"INTEGER", "TEXT", "REAL", "BLOB", "TIMESTAMP"}
VALID_FK_ACTIONS = {"CASCADE", "RESTRICT", "SET NULL", "NO ACTION", "SET DEFAULT"}


class MigrationError(Exception):
    """Exception raised when a migration operation fails."""
    pass


def error_exit(message):
    """Print error to stderr and exit with code 1."""
    print(f"Error: {message}", file=sys.stderr)
    sys.exit(1)


def is_valid_identifier(name):
    """Check if a name is a valid SQLite identifier (alphanumeric + underscore, starts with letter/underscore)."""
    if not name or not isinstance(name, str):
        return False
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', name))


def quote_identifier(name):
    """Quote a SQLite identifier to prevent SQL injection."""
    # Double any existing double quotes, then wrap in double quotes
    return '"' + name.replace('"', '""') + '"'


def validate_column(col, operation_type="create_table"):
    """Validate a column definition. Returns error message or None."""
    if not isinstance(col, dict):
        return "column must be an object"

    if "name" not in col:
        return "missing required field 'name' in column definition"
    if "type" not in col:
        return "missing required field 'type' in column definition"

    if not isinstance(col["name"], str) or not is_valid_identifier(col["name"]):
        return f"invalid column name: '{col.get('name')}'"
    if not isinstance(col["type"], str) or col["type"].upper() not in VALID_SQLITE_TYPES:
        return f"invalid column type: '{col.get('type')}'"

    # Validate optional boolean fields
    for bool_field in ("primary_key", "auto_increment", "not_null", "unique"):
        if bool_field in col and not isinstance(col[bool_field], bool):
            return f"field '{bool_field}' must be a boolean"

    # auto_increment must be on INTEGER primary key
    if col.get("auto_increment", False):
        if col["type"].upper() != "INTEGER":
            return "auto_increment can only be used with INTEGER type"
        if not col.get("primary_key", False):
            return "auto_increment can only be used with primary_key"

    return None


def validate_migration(migration):
    """Validate the migration JSON structure. Returns error message or None."""
    if not isinstance(migration, dict):
        return "migration must be a JSON object"

    if "version" not in migration:
        return "missing required field 'version'"
    if "description" not in migration:
        return "missing required field 'description'"
    if "operations" not in migration:
        return "missing required field 'operations'"

    if not isinstance(migration["version"], int) or migration["version"] <= 0:
        return "version must be a positive integer"
    if not isinstance(migration["description"], str):
        return "description must be a string"
    if not isinstance(migration["operations"], list):
        return "operations must be an array"
    if len(migration["operations"]) == 0:
        return "operations array must not be empty"

    for i, op in enumerate(migration["operations"]):
        if not isinstance(op, dict):
            return f"operation {i} must be an object"
        if "type" not in op:
            return f"operation {i}: missing required field 'type'"

        op_type = op["type"]

        if op_type == "create_table":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "columns" not in op:
                return f"operation {i}: missing required field 'columns'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"

            pk_count = 0
            for j, col in enumerate(op["columns"]):
                err = validate_column(col, "create_table")
                if err:
                    return f"operation {i}, column {j}: {err}"
                if col.get("primary_key", False):
                    pk_count += 1
            if pk_count > 1:
                return f"operation {i}: at most one column can have primary_key=true"

        elif op_type == "add_column":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"

            err = validate_column(op["column"], "add_column")
            if err:
                return f"operation {i}: {err}"

        elif op_type == "drop_column":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["column"], str) or not is_valid_identifier(op["column"]):
                return f"operation {i}: invalid column name '{op.get('column')}'"

        elif op_type == "transform_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "transformations" not in op:
                return f"operation {i}: missing required field 'transformations'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"

            if not isinstance(op["transformations"], list) or len(op["transformations"]) == 0:
                return f"operation {i}: transformations must be a non-empty array"

            for j, transform in enumerate(op["transformations"]):
                if not isinstance(transform, dict):
                    return f"operation {i}, transformation {j}: must be an object"
                if "column" not in transform:
                    return f"operation {i}, transformation {j}: missing required field 'column'"
                if "expression" not in transform:
                    return f"operation {i}, transformation {j}: missing required field 'expression'"
                if not isinstance(transform["column"], str) or not is_valid_identifier(transform["column"]):
                    return f"operation {i}, transformation {j}: invalid column name '{transform.get('column')}'"
                if not isinstance(transform["expression"], str):
                    return f"operation {i}, transformation {j}: expression must be a string"

        elif op_type == "migrate_column_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "from_column" not in op:
                return f"operation {i}: missing required field 'from_column'"
            if "to_column" not in op:
                return f"operation {i}: missing required field 'to_column'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["from_column"], str) or not is_valid_identifier(op["from_column"]):
                return f"operation {i}: invalid from_column name '{op.get('from_column')}'"
            if not isinstance(op["to_column"], str) or not is_valid_identifier(op["to_column"]):
                return f"operation {i}: invalid to_column name '{op.get('to_column')}'"

            if "default_value" in op and op["default_value"] is not None and not isinstance(op["default_value"], str):
                return f"operation {i}: default_value must be a string or null"

        elif op_type == "backfill_data":
            if "table" not in op:
                return f"operation {i}: missing required field 'table'"
            if "column" not in op:
                return f"operation {i}: missing required field 'column'"
            if "value" not in op:
                return f"operation {i}: missing required field 'value'"

            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["column"], str) or not is_valid_identifier(op["column"]):
                return f"operation {i}: invalid column name '{op.get('column')}'"
            if not isinstance(op["value"], str):
                return f"operation {i}: value must be a string"

            if "where" in op and not isinstance(op["where"], str):
                return f"operation {i}: where must be a string"

        elif op_type == "add_foreign_key":
            for req_field in ("table", "name", "columns", "references"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid foreign key name '{op.get('name')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"
            for j, col in enumerate(op["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid column name at index {j}"
            if not isinstance(op["references"], dict):
                return f"operation {i}: references must be an object"
            if "table" not in op["references"] or "columns" not in op["references"]:
                return f"operation {i}: references must have 'table' and 'columns'"
            if not isinstance(op["references"]["table"], str) or not is_valid_identifier(op["references"]["table"]):
                return f"operation {i}: invalid referenced table name"
            if not isinstance(op["references"]["columns"], list) or len(op["references"]["columns"]) == 0:
                return f"operation {i}: references.columns must be a non-empty array"
            if len(op["columns"]) != len(op["references"]["columns"]):
                return f"operation {i}: number of columns must match references.columns"
            for j, col in enumerate(op["references"]["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid referenced column name at index {j}"
            if "on_delete" in op:
                if not isinstance(op["on_delete"], str) or op["on_delete"] not in VALID_FK_ACTIONS:
                    return f"operation {i}: invalid on_delete action '{op.get('on_delete')}'"
            if "on_update" in op:
                if not isinstance(op["on_update"], str) or op["on_update"] not in VALID_FK_ACTIONS:
                    return f"operation {i}: invalid on_update action '{op.get('on_update')}'"

        elif op_type == "drop_foreign_key":
            for req_field in ("table", "name"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid foreign key name '{op.get('name')}'"

        elif op_type == "create_index":
            for req_field in ("name", "table", "columns"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid index name '{op.get('name')}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["columns"], list) or len(op["columns"]) == 0:
                return f"operation {i}: columns must be a non-empty array"
            for j, col in enumerate(op["columns"]):
                if not isinstance(col, str) or not is_valid_identifier(col):
                    return f"operation {i}: invalid column name at index {j}"
            if "unique" in op and not isinstance(op["unique"], bool):
                return f"operation {i}: unique must be a boolean"

        elif op_type == "drop_index":
            if "name" not in op:
                return f"operation {i}: missing required field 'name'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid index name '{op.get('name')}'"

        elif op_type == "add_check_constraint":
            for req_field in ("table", "name", "expression"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid constraint name '{op.get('name')}'"
            if not isinstance(op["expression"], str):
                return f"operation {i}: expression must be a string"

        elif op_type == "drop_check_constraint":
            for req_field in ("table", "name"):
                if req_field not in op:
                    return f"operation {i}: missing required field '{req_field}'"
            if not isinstance(op["table"], str) or not is_valid_identifier(op["table"]):
                return f"operation {i}: invalid table name '{op.get('table')}'"
            if not isinstance(op["name"], str) or not is_valid_identifier(op["name"]):
                return f"operation {i}: invalid constraint name '{op.get('name')}'"

        else:
            return f"operation {i}: unknown operation type '{op_type}'"

    return None


def build_column_sql(col):
    """Build the SQL fragment for a column definition."""
    parts = [quote_identifier(col["name"]), col["type"].upper()]

    if col.get("primary_key", False):
        parts.append("PRIMARY KEY")
        if col.get("auto_increment", False):
            parts.append("AUTOINCREMENT")

    if col.get("not_null", False):
        parts.append("NOT NULL")

    if col.get("unique", False):
        parts.append("UNIQUE")

    if "default" in col and col["default"] is not None:
        parts.append(f"DEFAULT {col['default']}")

    return " ".join(parts)


def get_table_info(conn, table_name):
    """Get column info for a table. Returns list of column info dicts."""
    cursor = conn.execute(f"PRAGMA table_info({quote_identifier(table_name)})")
    columns = []
    for row in cursor.fetchall():
        columns.append({
            "cid": row[0],
            "name": row[1],
            "type": row[2],
            "not_null": bool(row[3]),
            "default_value": row[4],
            "primary_key": bool(row[5]),
        })
    return columns


def table_exists(conn, table_name):
    """Check if a table exists in the database."""
    cursor = conn.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    return cursor.fetchone() is not None


def column_exists(conn, table_name, column_name):
    """Check if a column exists in a table."""
    columns = get_table_info(conn, table_name)
    return any(c["name"] == column_name for c in columns)


def get_column_names(conn, table_name):
    """Get list of column names for a table."""
    columns = get_table_info(conn, table_name)
    return [c["name"] for c in columns]


def index_exists(conn, index_name):
    """Check if an index exists in the database."""
    cursor = conn.execute(
        "SELECT name FROM sqlite_master WHERE type='index' AND name=?",
        (index_name,)
    )
    return cursor.fetchone() is not None


def get_table_foreign_keys(conn, table_name):
    """Get foreign key constraints for a table using PRAGMA foreign_key_list."""
    cursor = conn.execute(f"PRAGMA foreign_key_list({quote_identifier(table_name)})")
    fks = []
    for row in cursor.fetchall():
        fks.append({
            "id": row[0],        # Foreign key id (for composite FKs)
            "seq": row[1],       # Column sequence in composite FK
            "table": row[2],     # Referenced table
            "from": row[3],      # Column in this table
            "to": row[4],        # Column in referenced table
            "on_update": row[5],
            "on_delete": row[6],
            "match": row[7],
        })
    return fks


def get_foreign_key_id_by_name(conn, table_name, fk_name):
    """
    Get foreign key constraint info by name.
    SQLite doesn't store FK names directly, so we parse them from the CREATE TABLE SQL.
    Returns dict with 'id' (the FK id from pragma) and other info, or None if not found.
    """
    cursor = conn.execute(
        "SELECT sql FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    row = cursor.fetchone()
    if not row or not row[0]:
        return None

    sql = row[0]
    # Find CONSTRAINT <name> FOREIGN KEY pattern
    # Pattern matches: CONSTRAINT "name" or CONSTRAINT name
    import re
    pattern = r'CONSTRAINT\s+"?' + re.escape(fk_name) + r'"\s+FOREIGN\s+KEY\s*\(([^)]+)\)\s+REFERENCES\s+"?(\w+)"?\s*\(([^)]+)\)(?:\s+ON\s+DELETE\s+(CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?(?:\s+ON\s+UPDATE\s+(CASCADE|RESTRICT|SET\s+NULL|NO\s+ACTION|SET\s+DEFAULT))?'
    match = re.search(pattern, sql, re.IGNORECASE)
    if not match:
        return None

    columns_str = match.group(1)
    ref_table = match.group(2)
    ref_columns_str = match.group(3)
    on_delete = match.group(4)
    on_update = match.group(5)

    # Parse column names (remove quotes)
    columns = [c.strip().strip('"') for c in columns_str.split(',')]
    ref_columns = [c.strip().strip('"') for c in ref_columns_str.split(',')]

    # Find the FK id from pragma
    pragma_fks = get_table_foreign_keys(conn, table_name)
    for fk in pragma_fks:
        if fk["table"] == ref_table and fk["from"] == columns[0]:
            return {
                "id": fk["id"],
                "name": fk_name,
                "columns": columns,
                "references": {
                    "table": ref_table,
                    "columns": ref_columns
                },
                "on_delete": on_delete,
                "on_update": on_update
            }

    return None


def get_table_indexes(conn, table_name):
    """Get indexes for a table using PRAGMA index_list."""
    cursor = conn.execute(f"PRAGMA index_list({quote_identifier(table_name)})")
    indexes = []
    for row in cursor.fetchall():
        indexes.append({
            "name": row[1],
            "unique": bool(row[2]),
            "origin": row[3] if len(row) > 3 else "c",
        })
    return indexes


def get_index_columns(conn, index_name):
    """Get columns for an index using PRAGMA index_info."""
    cursor = conn.execute(f"PRAGMA index_info({quote_identifier(index_name)})")
    columns = []
    for row in cursor.fetchall():
        columns.append(row[2])  # Column name is at index 2
    return columns


def get_table_create_sql(conn, table_name):
    """Get the CREATE TABLE SQL for a table."""
    cursor = conn.execute(
        "SELECT sql FROM sqlite_master WHERE type='table' AND name=?",
        (table_name,)
    )
    row = cursor.fetchone()
    return row[0] if row else None


def get_check_constraints_from_sql(sql):
    """Parse check constraints from CREATE TABLE SQL."""
    import re
    constraints = []
    # Pattern for CONSTRAINT name CHECK (expression)
    pattern = r'CONSTRAINT\s+"?(\w+)"?\s+CHECK\s*\(([^)]+(?:\([^)]*\)[^)]*)*)\)'
    for match in re.finditer(pattern, sql, re.IGNORECASE):
        constraints.append({
            "name": match.group(1),
            "expression": match.group(2).strip()
        })
    return constraints


def check_constraint_exists(conn, table_name, constraint_name):
    """Check if a check constraint exists on a table."""
    sql = get_table_create_sql(conn, table_name)
    if not sql:
        return False
    constraints = get_check_constraints_from_sql(sql)
    return any(c["name"] == constraint_name for c in constraints)


def init_migrations_table(conn):
    """Create the _migrations tracking table if it doesn't exist."""
    conn.execute("""
        CREATE TABLE IF NOT EXISTS _migrations (
